// Auto-generated from world-cup-format-explained.html — preserves original markup verbatim.
import { useEffect } from 'react'
import StaticPage from '../../components/StaticPage.jsx'

const HTML = "<main class=\"pt-[110px] pb-16 max-w-[900px] mx-auto min-h-screen px-4\">\n\n      <!-- Breadcrumb + Title -->\n      <div class=\"bg-white/80 dark:bg-slate-800/80 border border-gray-200 dark:border-slate-700/50 rounded-2xl shadow-xl p-6 md:p-8 mb-8 backdrop-blur-md\">\n        <div class=\"flex items-center gap-2 text-xs font-bold uppercase tracking-wider text-primary mb-3\">\n          <a href=\"/\" class=\"hover:underline\">Home</a>\n          <span class=\"material-symbols-outlined text-[10px]\">chevron_right</span>\n          <span class=\"text-gray-400 dark:text-slate-500\">How the World Cup Works</span>\n        </div>\n        <h1 class=\"text-3xl md:text-4xl font-extrabold text-gray-900 dark:text-white tracking-tight mb-3\">\n          How the FIFA World Cup Works: Format, Groups &amp; Qualification\n        </h1>\n        <p class=\"text-xs md:text-sm font-bold uppercase tracking-wider text-gray-500 dark:text-slate-400 mb-2\">Plain-English explainer</p>\n        <p class=\"text-sm md:text-base text-gray-600 dark:text-slate-300 leading-relaxed\">\n          The World Cup is huge but the rules can look confusing if you only catch it once every four years. This guide breaks down the whole tournament in plain English: how many teams play, how the group stage works, what happens in the knockouts, and how qualification actually decides who's there. We also cover the brand-new <strong>48-team format</strong> that launches at the <a href=\"world-cup-2026.html\" class=\"text-[#ee335f] font-semibold hover:underline\">FIFA World Cup 2026</a> in the USA, Canada, and Mexico, including the new Round of 32 nobody had to think about before.\n        </p>\n      </div>\n\n      <article class=\"prose prose-sm md:prose-base max-w-none text-gray-700 dark:text-slate-300 leading-relaxed space-y-6\">\n\n        <!-- ════════════ Overview ════════════ -->\n        <h2 class=\"text-2xl md:text-3xl font-bold text-gray-900 dark:text-white mt-4 mb-2 tracking-tight\">\n          The Tournament in 30 Seconds\n        </h2>\n        <p>\n          The FIFA World Cup is played every four years. From 2026 onwards, <strong>48 national teams</strong> compete over roughly five weeks. The tournament is split into two phases: a <strong>group stage</strong> where teams play three matches each in mini-leagues of four, then a <strong>knockout stage</strong> where it's win-or-go-home until one team lifts the trophy. The winner is decided by a single final match. No second leg, no aggregates, no away goals. One game, 90 minutes (plus extra time and penalties if needed) and you're either the champion or you go home.\n        </p>\n\n        <p class=\"not-prose text-sm text-gray-500 dark:text-slate-400 italic my-6 border-l-2 border-[#ee335f]/40 pl-3\">\n          → Read also: <a href=\"fifa-world-cup-history.html\" class=\"text-[#ee335f] font-semibold hover:underline\">FIFA World Cup History: Every Winner &amp; Final</a>\n        </p>\n\n        <!-- ════════════ The 48-team Format ════════════ -->\n        <h2 class=\"text-2xl md:text-3xl font-bold text-gray-900 dark:text-white mt-10 mb-2 tracking-tight\">\n          The New 48-Team Format (From 2026 Onwards)\n        </h2>\n        <p>\n          For 24 years (1998 through 2022) the World Cup had 32 teams in 8 groups of 4, with the top 2 going through to a 16-team knockout. Clean and simple. From 2026, FIFA expanded the field to 48 teams. The new format looks like this:\n        </p>\n\n        <div class=\"not-prose overflow-x-auto -mx-2 md:mx-0\">\n          <table class=\"w-full text-sm md:text-base border-collapse\">\n            <thead>\n              <tr class=\"bg-primary text-white\">\n                <th class=\"text-left p-2 md:p-3 font-bold uppercase tracking-wider\">Phase</th>\n                <th class=\"text-left p-2 md:p-3 font-bold uppercase tracking-wider\">Teams Remaining</th>\n                <th class=\"text-left p-2 md:p-3 font-bold uppercase tracking-wider\">Matches</th>\n              </tr>\n            </thead>\n            <tbody>\n              <tr class=\"bg-white dark:bg-slate-900/40 border-b border-gray-200 dark:border-slate-800\"><td class=\"p-2 md:p-3 font-bold text-gray-900 dark:text-white\">Group Stage</td><td class=\"p-2 md:p-3\">48 → 32</td><td class=\"p-2 md:p-3\">72</td></tr>\n              <tr class=\"bg-gray-50 dark:bg-slate-900/20 border-b border-gray-200 dark:border-slate-800\"><td class=\"p-2 md:p-3 font-bold text-gray-900 dark:text-white\">Round of 32</td><td class=\"p-2 md:p-3\">32 → 16</td><td class=\"p-2 md:p-3\">16</td></tr>\n              <tr class=\"bg-white dark:bg-slate-900/40 border-b border-gray-200 dark:border-slate-800\"><td class=\"p-2 md:p-3 font-bold text-gray-900 dark:text-white\">Round of 16</td><td class=\"p-2 md:p-3\">16 → 8</td><td class=\"p-2 md:p-3\">8</td></tr>\n              <tr class=\"bg-gray-50 dark:bg-slate-900/20 border-b border-gray-200 dark:border-slate-800\"><td class=\"p-2 md:p-3 font-bold text-gray-900 dark:text-white\">Quarter-Finals</td><td class=\"p-2 md:p-3\">8 → 4</td><td class=\"p-2 md:p-3\">4</td></tr>\n              <tr class=\"bg-white dark:bg-slate-900/40 border-b border-gray-200 dark:border-slate-800\"><td class=\"p-2 md:p-3 font-bold text-gray-900 dark:text-white\">Semi-Finals</td><td class=\"p-2 md:p-3\">4 → 2</td><td class=\"p-2 md:p-3\">2</td></tr>\n              <tr class=\"bg-gray-50 dark:bg-slate-900/20 border-b border-gray-200 dark:border-slate-800\"><td class=\"p-2 md:p-3 font-bold text-gray-900 dark:text-white\">3rd-Place Play-off</td><td class=\"p-2 md:p-3\">2</td><td class=\"p-2 md:p-3\">1</td></tr>\n              <tr class=\"bg-white dark:bg-slate-900/40 border-l-4 border-accent\"><td class=\"p-2 md:p-3 font-bold text-gray-900 dark:text-white\">Final</td><td class=\"p-2 md:p-3\">2 → 1</td><td class=\"p-2 md:p-3\"><strong>1</strong></td></tr>\n            </tbody>\n          </table>\n        </div>\n\n        <p>\n          That's <strong>104 matches in total</strong>, up from 64 under the old format. The winning team plays <strong>8 games</strong> to lift the trophy, up from 7. One extra match might not sound like much, but spread across the same 39-day window with travel between three host nations, it's a serious physical step up.\n        </p>\n\n        <!-- ════════════ Group Stage ════════════ -->\n        <h2 class=\"text-2xl md:text-3xl font-bold text-gray-900 dark:text-white mt-12 mb-2 tracking-tight\">\n          The Group Stage Explained\n        </h2>\n        <p>\n          The 48 qualified teams are split into <strong>12 groups of 4 teams</strong>, labelled Group A through Group L. Within each group, every team plays the other three once. That's three games per team, six games per group. Results convert to points using a standard table:\n        </p>\n\n        <ul class=\"list-disc pl-6 space-y-2\">\n          <li><strong>Win:</strong> 3 points</li>\n          <li><strong>Draw:</strong> 1 point each</li>\n          <li><strong>Loss:</strong> 0 points</li>\n        </ul>\n\n        <p>\n          At the end of the group stage, teams are ranked 1 to 4 in each group. The <strong>top 2</strong> from every group automatically qualify for the Round of 32 (that's 24 teams). The <strong>8 best third-placed teams</strong> across all groups also advance. Together those 32 teams form the knockout bracket.\n        </p>\n\n        <h3 class=\"text-xl md:text-2xl font-bold text-gray-900 dark:text-white mt-8 mb-2\">Tiebreakers If Teams Are Level on Points</h3>\n        <p>\n          What happens if two or three teams finish on the same points? FIFA applies these rules in this exact order:\n        </p>\n\n        <ol class=\"list-decimal pl-6 space-y-2\">\n          <li><strong>Goal difference</strong> across all group matches (goals scored minus goals conceded).</li>\n          <li><strong>Goals scored</strong> across all group matches.</li>\n          <li><strong>Head-to-head result</strong> if only two teams are tied.</li>\n          <li><strong>Head-to-head mini-table</strong> (points, goal difference, goals scored) if three or more are tied.</li>\n          <li><strong>Fair play points</strong> (yellow and red cards count against you).</li>\n          <li><strong>Drawing of lots</strong> by FIFA (basically a coin flip). This has only happened once in tournament history (Italy v Soviet Union, 1990 group stage seeding).</li>\n        </ol>\n\n        <h3 class=\"text-xl md:text-2xl font-bold text-gray-900 dark:text-white mt-8 mb-2\">How \"8 Best Third-Placed\" Teams Are Ranked</h3>\n        <p>\n          This is where it gets interesting. After the group stage, all 12 third-placed teams are ranked head-to-head using points, goal difference, goals scored, and fair play. The top 8 of those 12 go through to the Round of 32. The other 4 go home. Coaches now have to think strategically: finishing third isn't necessarily a disaster, but it's not safe either. Three points and a respectable goal difference is usually enough to scrape into the last 32.\n        </p>\n\n        <p class=\"not-prose text-sm text-gray-500 dark:text-slate-400 italic my-6 border-l-2 border-[#ee335f]/40 pl-3\">\n          → Read also: <a href=\"world-cup-2026.html\" class=\"text-[#ee335f] font-semibold hover:underline\">World Cup 2026 Full Schedule &amp; Group Stage Dates</a>\n        </p>\n\n        <!-- ════════════ Knockouts ════════════ -->\n        <h2 class=\"text-2xl md:text-3xl font-bold text-gray-900 dark:text-white mt-12 mb-2 tracking-tight\">\n          The Knockout Stage Explained\n        </h2>\n        <p>\n          Once the group stage finishes, every match is win-or-go-home. No second legs, no aggregate scores. The brackets are seeded based on how teams finished in their groups, with group winners theoretically getting easier paths.\n        </p>\n\n        <h3 class=\"text-xl md:text-2xl font-bold text-gray-900 dark:text-white mt-8 mb-2\">If the Match Is Tied After 90 Minutes</h3>\n        <p>\n          Three steps, in this order:\n        </p>\n\n        <ol class=\"list-decimal pl-6 space-y-2\">\n          <li><strong>Extra time:</strong> Two 15-minute halves of additional play, no Golden Goal (that rule was scrapped in 2004). The match runs the full 30 minutes regardless of who scores.</li>\n          <li><strong>Penalty shootout:</strong> Best of 5 spot kicks per side, alternating teams. If still tied after 5, sudden death takes over (each team takes one kick, first to lead at the end of a round wins).</li>\n          <li><strong>That's it.</strong> One team advances, the other is eliminated.</li>\n        </ol>\n\n        <h3 class=\"text-xl md:text-2xl font-bold text-gray-900 dark:text-white mt-8 mb-2\">The Path to the Trophy</h3>\n        <p>\n          If you've qualified directly from your group, here's what's ahead of you to win the World Cup:\n        </p>\n\n        <ul class=\"list-disc pl-6 space-y-2\">\n          <li>3 group-stage matches</li>\n          <li>Round of 32 (1 game)</li>\n          <li>Round of 16 (1 game)</li>\n          <li>Quarter-final (1 game)</li>\n          <li>Semi-final (1 game)</li>\n          <li>Final (1 game)</li>\n        </ul>\n\n        <p>\n          That's <strong>8 matches</strong> across 39 days. Squads carry 26 players to manage rotation, injuries, and suspensions (any player who picks up 2 yellow cards in different matches is suspended for the next game). Manage your squad badly and a key player misses the final.\n        </p>\n\n        <!-- ════════════ Qualification ════════════ -->\n        <h2 class=\"text-2xl md:text-3xl font-bold text-gray-900 dark:text-white mt-12 mb-2 tracking-tight\">\n          How Teams Qualify for the World Cup\n        </h2>\n        <p>\n          With 211 FIFA member nations and only 48 slots, qualification is brutal. The world is split into <strong>6 confederations</strong>, and each one gets a fixed number of direct qualification spots. The hosts get automatic places. The remaining slots go through 2-year qualifying campaigns within each confederation. Here's how the 48 places break down for 2026:\n        </p>\n\n        <div class=\"not-prose overflow-x-auto -mx-2 md:mx-0\">\n          <table class=\"w-full text-xs md:text-sm border-collapse\">\n            <thead>\n              <tr class=\"bg-primary text-white\">\n                <th class=\"text-left p-2 md:p-3 font-bold uppercase tracking-wider\">Confederation</th>\n                <th class=\"text-left p-2 md:p-3 font-bold uppercase tracking-wider\">Region</th>\n                <th class=\"text-left p-2 md:p-3 font-bold uppercase tracking-wider\">Direct Slots</th>\n              </tr>\n            </thead>\n            <tbody>\n              <tr class=\"bg-white dark:bg-slate-900/40 border-b border-gray-200 dark:border-slate-800\"><td class=\"p-2 md:p-3 font-bold\">UEFA</td><td class=\"p-2 md:p-3\">Europe</td><td class=\"p-2 md:p-3\">16</td></tr>\n              <tr class=\"bg-gray-50 dark:bg-slate-900/20 border-b border-gray-200 dark:border-slate-800\"><td class=\"p-2 md:p-3 font-bold\">CAF</td><td class=\"p-2 md:p-3\">Africa</td><td class=\"p-2 md:p-3\">9</td></tr>\n              <tr class=\"bg-white dark:bg-slate-900/40 border-b border-gray-200 dark:border-slate-800\"><td class=\"p-2 md:p-3 font-bold\">AFC</td><td class=\"p-2 md:p-3\">Asia</td><td class=\"p-2 md:p-3\">8</td></tr>\n              <tr class=\"bg-gray-50 dark:bg-slate-900/20 border-b border-gray-200 dark:border-slate-800\"><td class=\"p-2 md:p-3 font-bold\">CONMEBOL</td><td class=\"p-2 md:p-3\">South America</td><td class=\"p-2 md:p-3\">6</td></tr>\n              <tr class=\"bg-white dark:bg-slate-900/40 border-b border-gray-200 dark:border-slate-800\"><td class=\"p-2 md:p-3 font-bold\">CONCACAF</td><td class=\"p-2 md:p-3\">North &amp; Central America, Caribbean</td><td class=\"p-2 md:p-3\">3 + 3 hosts (USA, Canada, Mexico)</td></tr>\n              <tr class=\"bg-gray-50 dark:bg-slate-900/20 border-b border-gray-200 dark:border-slate-800\"><td class=\"p-2 md:p-3 font-bold\">OFC</td><td class=\"p-2 md:p-3\">Oceania</td><td class=\"p-2 md:p-3\">1</td></tr>\n              <tr class=\"bg-white dark:bg-slate-900/40\"><td class=\"p-2 md:p-3 font-bold\">Inter-confederation play-off</td><td class=\"p-2 md:p-3\">6-team mini tournament</td><td class=\"p-2 md:p-3\">2 (last 2 places)</td></tr>\n            </tbody>\n          </table>\n        </div>\n\n        <p>\n          That's <strong>48 in total</strong>. The 2 final places are decided by an inter-confederation play-off tournament hosted in one of the host nations a few months before the World Cup itself.\n        </p>\n\n        <h3 class=\"text-xl md:text-2xl font-bold text-gray-900 dark:text-white mt-8 mb-2\">How Each Confederation Runs Qualifying</h3>\n        <p>\n          Every confederation runs its own qualifying competition with different formats. Here's how the main ones work:\n        </p>\n\n        <ul class=\"list-disc pl-6 space-y-2\">\n          <li><strong>UEFA:</strong> 54 teams split into 12 groups. Group winners qualify directly (12 places). Group runners-up plus 4 best UEFA Nations League group winners go into a play-off bracket for the final 4 slots.</li>\n          <li><strong>CONMEBOL:</strong> All 10 South American nations play each other home and away in a 2-year round-robin league. Top 6 qualify, 7th place goes to the inter-confederation play-off.</li>\n          <li><strong>CAF:</strong> 54 teams split into 9 groups. Each group winner qualifies. Top 4 group runners-up go into an African play-off for one final place that leads to the inter-confederation play-off.</li>\n          <li><strong>AFC:</strong> Multi-round elimination. 47 teams enter, dropping to 36, then 18 in the third round (the most-watched phase). Top 2 of each group of 6 qualify (8 teams), and a play-off decides the rest.</li>\n          <li><strong>CONCACAF:</strong> The 3 hosts (USA, Canada, Mexico) automatically qualify. The other 32 teams compete for 3 direct slots through multi-round qualifying.</li>\n          <li><strong>OFC:</strong> 11 small Oceania nations compete for 1 direct slot. The runner-up goes to the inter-confederation play-off.</li>\n        </ul>\n\n        <h3 class=\"text-xl md:text-2xl font-bold text-gray-900 dark:text-white mt-8 mb-2\">The Inter-confederation Play-off</h3>\n        <p>\n          A six-team mini tournament. Two teams are seeded directly into single-leg finals. The other four play a single-leg semi-final, then meet a seeded team in a final. Two winners qualify for the World Cup. It's brutal and decided by one match each. This is where the genuine underdog stories often come from: New Zealand, Peru, Australia, and Costa Rica have all qualified via this route in past tournaments.\n        </p>\n\n        <p class=\"not-prose text-sm text-gray-500 dark:text-slate-400 italic my-6 border-l-2 border-[#ee335f]/40 pl-3\">\n          → Read also: <a href=\"how-to-watch-football-mena.html\" class=\"text-[#ee335f] font-semibold hover:underline\">How to Watch Football in MENA: beIN Sports &amp; Free Options</a>\n        </p>\n\n        <!-- ════════════ Squad Rules ════════════ -->\n        <h2 class=\"text-2xl md:text-3xl font-bold text-gray-900 dark:text-white mt-12 mb-2 tracking-tight\">\n          Squad Rules &amp; In-Match Regulations\n        </h2>\n        <p>\n          A few rules worth knowing if you want to actually follow the tournament closely.\n        </p>\n\n        <h3 class=\"text-xl md:text-2xl font-bold text-gray-900 dark:text-white mt-8 mb-2\">Squad Size</h3>\n        <p>\n          Each team can name <strong>26 players</strong> in their squad (up from 23 before COVID). At least 3 must be goalkeepers. A team must submit their final 26 to FIFA 6 days before the opening game.\n        </p>\n\n        <h3 class=\"text-xl md:text-2xl font-bold text-gray-900 dark:text-white mt-8 mb-2\">Substitutions</h3>\n        <p>\n          Teams get <strong>5 substitutions per match</strong>, made across a maximum of 3 stoppages. In knockout matches that go to extra time, teams get <strong>1 additional sub</strong> for the 30-minute extra period. Concussion substitutions don't count toward your normal 5 (introduced in 2022).\n        </p>\n\n        <h3 class=\"text-xl md:text-2xl font-bold text-gray-900 dark:text-white mt-8 mb-2\">VAR</h3>\n        <p>\n          The Video Assistant Referee system is used at every match. VAR can review and correct decisions on goals, penalties, red cards, and cases of mistaken identity. The on-field referee still makes the final call after watching the pitch-side monitor.\n        </p>\n\n        <h3 class=\"text-xl md:text-2xl font-bold text-gray-900 dark:text-white mt-8 mb-2\">Semi-Automated Offside</h3>\n        <p>\n          First used at Qatar 2022 and continued in 2026. Cameras track 29 data points on every player, plus a sensor inside the match ball. The system gives VAR officials an automated offside indication within seconds. Manual review by the referee still confirms the final decision.\n        </p>\n\n        <h3 class=\"text-xl md:text-2xl font-bold text-gray-900 dark:text-white mt-8 mb-2\">Yellow Card &amp; Suspension Rules</h3>\n        <p>\n          Two yellow cards across different matches = 1-match ban. Yellow card slates are wiped clean <strong>after the quarter-finals</strong>, so players don't miss the final because of a yellow in the group stage. Direct red cards lead to an automatic ban of at least 1 match, sometimes longer depending on the offence.\n        </p>\n\n        <!-- ════════════ Prize Money ════════════ -->\n        <h2 class=\"text-2xl md:text-3xl font-bold text-gray-900 dark:text-white mt-12 mb-2 tracking-tight\">\n          Prize Money &amp; What's at Stake\n        </h2>\n        <p>\n          FIFA distributes record-breaking prize pools that grow every tournament. For the 2022 World Cup the total prize fund was around <strong>$440 million</strong>. The 2026 edition is expected to top <strong>$700 million</strong>.\n        </p>\n\n        <ul class=\"list-disc pl-6 space-y-2\">\n          <li><strong>Winner:</strong> approximately $42 million (going up for 2026)</li>\n          <li><strong>Runner-up:</strong> approximately $30 million</li>\n          <li><strong>3rd place:</strong> approximately $27 million</li>\n          <li><strong>4th place:</strong> approximately $25 million</li>\n          <li><strong>Quarter-finalists:</strong> approximately $17 million each</li>\n          <li><strong>Round of 16:</strong> approximately $13 million each</li>\n          <li><strong>Group stage exit:</strong> approximately $9 million each (with the new Round of 32, this drops slightly for 2026)</li>\n        </ul>\n\n        <p>\n          On top of the prize money, every nation gets a <strong>$1.5 million preparation grant</strong> from FIFA. Plus clubs that release players to international duty get compensation for any days their players spend at the tournament (about $10,000 per player per day in 2022).\n        </p>\n\n        <!-- ════════════ FAQ ════════════ -->\n        <h2 class=\"text-2xl md:text-3xl font-bold text-gray-900 dark:text-white mt-12 mb-2 tracking-tight\">\n          FAQs\n        </h2>\n\n        <details class=\"border border-gray-200 dark:border-slate-800 rounded-xl bg-white dark:bg-slate-900/50 overflow-hidden group\">\n          <summary class=\"flex justify-between items-center px-5 py-4 cursor-pointer font-bold text-sm md:text-base text-gray-800 dark:text-slate-200 list-none select-none\">\n            How many teams play in the World Cup now?\n            <span class=\"material-symbols-outlined text-primary transition-transform group-open:rotate-180\" style=\"font-size: 20px\">expand_more</span>\n          </summary>\n          <p class=\"px-5 pb-4 text-sm md:text-base text-gray-600 dark:text-slate-400 leading-relaxed\">\n            From 2026 onwards, <strong>48 teams</strong> play in the FIFA World Cup, up from 32 at Qatar 2022. The tournament expands to 104 matches across 39 days. Full breakdown on our <a href=\"world-cup-2026.html\" class=\"text-primary font-semibold hover:underline\">World Cup 2026 page</a>.\n          </p>\n        </details>\n\n        <details class=\"border border-gray-200 dark:border-slate-800 rounded-xl bg-white dark:bg-slate-900/50 overflow-hidden group\">\n          <summary class=\"flex justify-between items-center px-5 py-4 cursor-pointer font-bold text-sm md:text-base text-gray-800 dark:text-slate-200 list-none select-none\">\n            How many matches does the winning team play?\n            <span class=\"material-symbols-outlined text-primary transition-transform group-open:rotate-180\" style=\"font-size: 20px\">expand_more</span>\n          </summary>\n          <p class=\"px-5 pb-4 text-sm md:text-base text-gray-600 dark:text-slate-400 leading-relaxed\">\n            Under the new 48-team format, the World Cup winners play <strong>8 matches</strong>: 3 group games plus 5 knockout rounds (Round of 32, Round of 16, quarter-final, semi-final, final). That's one more than the old 32-team format.\n          </p>\n        </details>\n\n        <details class=\"border border-gray-200 dark:border-slate-800 rounded-xl bg-white dark:bg-slate-900/50 overflow-hidden group\">\n          <summary class=\"flex justify-between items-center px-5 py-4 cursor-pointer font-bold text-sm md:text-base text-gray-800 dark:text-slate-200 list-none select-none\">\n            What happens if two teams are tied in a group?\n            <span class=\"material-symbols-outlined text-primary transition-transform group-open:rotate-180\" style=\"font-size: 20px\">expand_more</span>\n          </summary>\n          <p class=\"px-5 pb-4 text-sm md:text-base text-gray-600 dark:text-slate-400 leading-relaxed\">\n            Tiebreakers go in this order: goal difference, goals scored, head-to-head result (or head-to-head mini-table for 3-way ties), fair play points, then drawing of lots. Goal difference decides most of them.\n          </p>\n        </details>\n\n        <details class=\"border border-gray-200 dark:border-slate-800 rounded-xl bg-white dark:bg-slate-900/50 overflow-hidden group\">\n          <summary class=\"flex justify-between items-center px-5 py-4 cursor-pointer font-bold text-sm md:text-base text-gray-800 dark:text-slate-200 list-none select-none\">\n            Why are there 8 best third-placed teams?\n            <span class=\"material-symbols-outlined text-primary transition-transform group-open:rotate-180\" style=\"font-size: 20px\">expand_more</span>\n          </summary>\n          <p class=\"px-5 pb-4 text-sm md:text-base text-gray-600 dark:text-slate-400 leading-relaxed\">\n            With 12 groups, the top 2 from each group (24 teams) plus 8 best third-placed teams gives you exactly 32 for the Round of 32. The 8 best third-placed teams are ranked by points, goal difference, goals scored, and fair play.\n          </p>\n        </details>\n\n        <details class=\"border border-gray-200 dark:border-slate-800 rounded-xl bg-white dark:bg-slate-900/50 overflow-hidden group\">\n          <summary class=\"flex justify-between items-center px-5 py-4 cursor-pointer font-bold text-sm md:text-base text-gray-800 dark:text-slate-200 list-none select-none\">\n            Do hosts automatically qualify?\n            <span class=\"material-symbols-outlined text-primary transition-transform group-open:rotate-180\" style=\"font-size: 20px\">expand_more</span>\n          </summary>\n          <p class=\"px-5 pb-4 text-sm md:text-base text-gray-600 dark:text-slate-400 leading-relaxed\">\n            Yes. Host nations get automatic places in the World Cup. For 2026 that means <strong>USA, Canada, and Mexico</strong> all qualify directly. With 3 hosts, that's 3 of the 48 spots filled before qualifying even begins.\n          </p>\n        </details>\n\n        <details class=\"border border-gray-200 dark:border-slate-800 rounded-xl bg-white dark:bg-slate-900/50 overflow-hidden group\">\n          <summary class=\"flex justify-between items-center px-5 py-4 cursor-pointer font-bold text-sm md:text-base text-gray-800 dark:text-slate-200 list-none select-none\">\n            What is the inter-confederation play-off?\n            <span class=\"material-symbols-outlined text-primary transition-transform group-open:rotate-180\" style=\"font-size: 20px\">expand_more</span>\n          </summary>\n          <p class=\"px-5 pb-4 text-sm md:text-base text-gray-600 dark:text-slate-400 leading-relaxed\">\n            A 6-team mini tournament that decides the final 2 World Cup spots. It's hosted in one of the host nations a few months before the World Cup itself. Two teams are seeded directly into single-leg finals. The other four play a semi-final, then a final. The 2 winners go to the World Cup.\n          </p>\n        </details>\n\n        <details class=\"border border-gray-200 dark:border-slate-800 rounded-xl bg-white dark:bg-slate-900/50 overflow-hidden group\">\n          <summary class=\"flex justify-between items-center px-5 py-4 cursor-pointer font-bold text-sm md:text-base text-gray-800 dark:text-slate-200 list-none select-none\">\n            How many substitutions are allowed?\n            <span class=\"material-symbols-outlined text-primary transition-transform group-open:rotate-180\" style=\"font-size: 20px\">expand_more</span>\n          </summary>\n          <p class=\"px-5 pb-4 text-sm md:text-base text-gray-600 dark:text-slate-400 leading-relaxed\">\n            <strong>5 substitutions per match</strong>, made across a maximum of 3 stoppages plus halftime. In knockout matches going to extra time, teams get 1 extra substitute for that period. Concussion substitutions don't count against the limit.\n          </p>\n        </details>\n\n        <details class=\"border border-gray-200 dark:border-slate-800 rounded-xl bg-white dark:bg-slate-900/50 overflow-hidden group\">\n          <summary class=\"flex justify-between items-center px-5 py-4 cursor-pointer font-bold text-sm md:text-base text-gray-800 dark:text-slate-200 list-none select-none\">\n            Why was the format expanded?\n            <span class=\"material-symbols-outlined text-primary transition-transform group-open:rotate-180\" style=\"font-size: 20px\">expand_more</span>\n          </summary>\n          <p class=\"px-5 pb-4 text-sm md:text-base text-gray-600 dark:text-slate-400 leading-relaxed\">\n            FIFA wanted to grow the tournament's global reach and revenue. More teams means more nations involved, more matches to broadcast, more sponsorship value, and more countries with a real chance of qualifying. Critics worry about diluting quality, but the new Round of 32 keeps the knockout stakes high right from the start.\n          </p>\n        </details>\n\n        <h2 class=\"text-2xl md:text-3xl font-bold text-gray-900 dark:text-white mt-12 mb-3 tracking-tight\">Related Guides</h2>\n        <div class=\"not-prose grid grid-cols-1 md:grid-cols-3 gap-3\">\n          <a href=\"world-cup-2026.html\" class=\"block bg-white dark:bg-slate-900/40 border border-gray-200 dark:border-slate-800 rounded-xl p-4 hover:border-[#ee335f] dark:hover:border-[#ee335f] hover:shadow-md transition-all\">\n            <h3 class=\"text-sm md:text-base font-bold text-gray-900 dark:text-white mb-1 leading-snug\">World Cup 2026 Schedule &amp; Fixtures</h3>\n            <p class=\"text-xs text-gray-500 dark:text-slate-400 leading-relaxed\">Match calendar, qualified teams, host stadiums, and where to watch live across USA, Canada, and Mexico.</p>\n          </a>\n          <a href=\"fifa-world-cup-history.html\" class=\"block bg-white dark:bg-slate-900/40 border border-gray-200 dark:border-slate-800 rounded-xl p-4 hover:border-[#ee335f] dark:hover:border-[#ee335f] hover:shadow-md transition-all\">\n            <h3 class=\"text-sm md:text-base font-bold text-gray-900 dark:text-white mb-1 leading-snug\">FIFA World Cup History</h3>\n            <p class=\"text-xs text-gray-500 dark:text-slate-400 leading-relaxed\">Every winner, host, and iconic final from Uruguay 1930 to Argentina 2022. The complete tournament history.</p>\n          </a>\n          <a href=\"world-cup-top-scorers-all-time.html\" class=\"block bg-white dark:bg-slate-900/40 border border-gray-200 dark:border-slate-800 rounded-xl p-4 hover:border-[#ee335f] dark:hover:border-[#ee335f] hover:shadow-md transition-all\">\n            <h3 class=\"text-sm md:text-base font-bold text-gray-900 dark:text-white mb-1 leading-snug\">Top World Cup Goalscorers Ever</h3>\n            <p class=\"text-xs text-gray-500 dark:text-slate-400 leading-relaxed\">The all-time goal-scoring leaderboard, from Just Fontaine and Klose to Messi, Mbappé, and the modern era.</p>\n          </a>\n        </div>\n\n      </article>\n    </main>"

